```
function applyOptions(instance, options, ...) {
  // 1. 处理 mixins / extends (递归)

  // 2. 处理 inject
  if (options.inject) { ... }

  // 3. 处理 data
  if (data) { 
    const dataFn = data
    const dataObj = dataFn.call(instance.proxy)
    // ...
  }

  // 4. 处理 computed
  // 5. 处理 methods
  // 6. 处理 watch
  // 7. 处理 lifecycle hooks
}
```

