```typescript
export function applyOptions(
  instance: ComponentInternalInstance,
  options: ComponentOptions,
  ...
) {
  // ...

  // data
  if (dataOptions) {
    // ...
    const data = dataOptions.call(instance.proxy)
    // ...
  }

  // lifecycle hooks
  // ...

  // methods
  if (methodsOptions) {
    for (const key in methodsOptions) {
      const method = methodsOptions[key]
      // ...
      instance.proxy![key] = method.bind(instance.proxy)
    }
  }
}
```

